#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long start, end, d;
        if (scanf("%lld %lld %lld", &start, &end, &d) != 3) break;
        if (d < 0) d = -d; // use positive divisor
        printf("[");
        int firstPrinted = 1;
        if (start <= end) {
            long long mod = start % d;
            long long firstMul;
            if (mod == 0) {
                firstMul = start;
            } else if (start >= 0) {
                firstMul = start + (d - mod);
            } else {
                firstMul = start - mod; // start negative
            }
            for (long long x = firstMul; x <= end; x += d) {
                if (firstPrinted) {
                    printf("%lld", x);
                    firstPrinted = 0;
                } else {
                    printf(", %lld", x);
                }
            }
        }
        printf("]\n");
    }
    return 0;
}

