#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        start = int(next(it))
        end = int(next(it))
        d = int(next(it))
        d = abs(d)
        res = []
        if start <= end:
            mod = start % d
            if mod == 0:
                first = start
            else:
                first = start + (d - mod) if start >= 0 else start - mod
            x = first
            while x <= end:
                res.append(x)
                x += d
        out_lines.append(str(res))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

